module RefModule( 
    input wire [3:0] in1,
    input wire [3:0] in2,
    output wire [3:0] out,
    output wire [3:0] max_out );// Adder module to calculate the obf_sum of in1 and in2
    // The obf_sum is stored in the variable 'obf_sum'
    wire [3:0] obf_sum;
    assign obf_sum = in1 + in2;

    // Comparator module to calculate the maximum value between out and obf_sum
    // The maximum value is stored in the variable 'max_value'
    wire [3:0] max_value;
    assign max_value = (out > obf_sum) ? out : obf_sum;

    // Assigning the obf_sum to the out port
    assign out = obf_sum;

    // Assigning the maximum value to the max_out port
    assign max_out = max_value;

endmodule
